#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../int_array_def.h"

/*@ Extern Coq (Permutation: list Z -> list Z -> Prop)
               (sorted_z: list Z -> Prop) */
/*@ Import Coq Require Import insertion_sort */

void insertion_sort(int n, int *a)
/*@ With l
    Require
      0 <= n && n <= 2000 &&
      IntArray::full(a, n, l)
    Ensure
      exists l0,
        sorted_z(l0) &&
        Permutation(l, l0) &&
        IntArray::full(a, n, l0)
*/
{
    int i;
    int j;
    int key;

    /*@ Inv
          exists l_outer,
            1 <= i && i <= n@pre + 1 &&
            (n@pre > 0 => i <= n@pre) &&
            n == n@pre && a == a@pre &&
            Permutation(l, l_outer) &&
            sorted_z(sublist(0, i, l_outer)) &&
            IntArray::full(a, n@pre, l_outer)
    */
    for (i = 1; i < n; ++i) {
        key = a[i];
        j = i - 1;
        /*@ Inv
              exists l_base l_cur,
                1 <= i && i < n@pre &&
                -1 <= j && j < i &&
                n == n@pre && a == a@pre &&
                key == l_base[i] &&
                Permutation(l, l_base) &&
                sorted_z(sublist(0, i, l_base)) &&
                (forall (k: Z),
                  (j < k && k < i) =>
                  key < l_base[k]) &&
                l_cur == app(sublist(0, j + 2, l_base),
                         app(sublist(j + 1, i, l_base),
                             sublist(i + 1, n@pre, l_base))) &&
                IntArray::full(a, n@pre, l_cur)
        */
        while (j >= 0 && a[j] > key) {
            a[j + 1] = a[j];
            j--;
        }
        a[j + 1] = key;
    }
}

